package com.finance.tracker.budget;
import com.finance.tracker.user.User; import jakarta.persistence.*; import java.math.BigDecimal;
@Entity @Table(name="budgets",uniqueConstraints=@UniqueConstraint(columnNames={"user_id","category","month","year"})) public class Budget { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(optional=false,fetch=FetchType.LAZY) @JoinColumn(name="user_id") private User user; @Column(nullable=false,length=80) private String category; @Column(nullable=false,precision=14,scale=2) private BigDecimal monthlyLimit; @Column(nullable=false) private int month; @Column(nullable=false) private int year; public Long getId(){return id;} public User getUser(){return user;} public void setUser(User v){user=v;} public String getCategory(){return category;} public void setCategory(String v){category=v;} public BigDecimal getMonthlyLimit(){return monthlyLimit;} public void setMonthlyLimit(BigDecimal v){monthlyLimit=v;} public int getMonth(){return month;} public void setMonth(int v){month=v;} public int getYear(){return year;} public void setYear(int v){year=v;} }
